import{_ as t,o as a,c as i,a0 as s}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"Configure Event Settings","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/event-settings.md","filePath":"how-to/event-settings.md"}'),n={name:"how-to/event-settings.md"};function l(o,e,r,c,h,p){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="configure-event-settings" tabindex="-1">Configure Event Settings <a class="header-anchor" href="#configure-event-settings" aria-label="Permalink to &quot;Configure Event Settings&quot;">​</a></h1><p>Use <strong>Event Settings</strong> when you want to control how an event behaves beyond its name and colors.</p><blockquote><p>Screenshot placeholder: event-settings.png</p></blockquote><h2 id="what-is-in-the-interface-today" tabindex="-1">What is in the interface today <a class="header-anchor" href="#what-is-in-the-interface-today" aria-label="Permalink to &quot;What is in the interface today&quot;">​</a></h2><p>The current settings page lets you configure these real, visible controls:</p><ul><li>name, category, icon, badge label, colors, and image URL</li><li>description and instructions</li><li>score label, score unit, and min/max score range</li><li>duration style: single-session, multi-day, or multi-stage</li><li>score entry mode: single score, cumulative total, or daily delta</li><li>default duration in days</li><li>multi-stage defaults such as stage count, stage labels, and whether import requires stage or stage date</li><li>membership snapshot mode</li><li>membership change policy</li><li>new joiner policy</li><li>leave policy</li><li>visibility toggles for dashboard, player analytics, event analytics, activity, and rewards</li><li>score-threshold rules</li></ul><h2 id="membership-and-policy-settings" tabindex="-1">Membership and policy settings <a class="header-anchor" href="#membership-and-policy-settings" aria-label="Permalink to &quot;Membership and policy settings&quot;">​</a></h2><p>These settings decide who counts in an instance and how the tracker reacts when alliance membership changes.</p><p>The current interface includes:</p><ul><li><strong>Snapshot mode</strong></li><li><strong>Membership change policy</strong></li><li><strong>New joiner policy</strong></li><li><strong>Leave policy</strong></li></ul><p>Read <a href="./../reference/participant-eligibility.html">Participant Eligibility Statuses</a> if you want to understand the results these policies can produce inside an instance.</p><h2 id="multi-stage-settings" tabindex="-1">Multi-stage settings <a class="header-anchor" href="#multi-stage-settings" aria-label="Permalink to &quot;Multi-stage settings&quot;">​</a></h2><p>For multi-stage events, the interface also exposes:</p><ul><li>default stage count</li><li>stage labels</li><li>whether stage selection is required on import</li><li>whether stage date is required on import</li></ul><p>This is especially important for events such as Alliance Brawl.</p><h2 id="what-is-not-yet-exposed-as-a-separate-interface-control" tabindex="-1">What is not yet exposed as a separate interface control <a class="header-anchor" href="#what-is-not-yet-exposed-as-a-separate-interface-control" aria-label="Permalink to &quot;What is not yet exposed as a separate interface control&quot;">​</a></h2><p>Some template-specific settings exist behind the scenes, especially for special templates such as Sanctuary Battle. Those deeper schema-level options are <strong>not yet available in the interface as separate controls</strong>.</p><p>What the interface does now do is preserve those special settings correctly when you save, customize, or review a template proposal. For Sanctuary Battle, the page also shows a clearer control-event warning so it is less likely to be mistaken for a normal score race.</p><p>So if you were expecting a raw JSON editor or a long list of technical event flags, that is still not the current user-facing design.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>change one event behavior at a time</li><li>save, then create or review an instance to confirm the result feels right</li><li>use the event-specific docs before changing a default template heavily</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./edit-event-template.html">Edit an Event Template</a></li><li><a href="./../events/default-events.html">The Default Events</a></li><li><a href="./../reference/participant-eligibility.html">Participant Eligibility Statuses</a></li></ul>',23)])])}const u=t(n,[["render",l]]);export{g as __pageData,u as default};
